INSERT INTO clinic_services (category, name, description, target_audience, cautions, base_price, is_active)
VALUES 
  ('Botox', 'Botox เกาหลี 50U', 'โปรโมชั่นพิเศษ โบท็อกซ์เกาหลี 50U ลดกราม หรือริ้วรอย', 'ผู้ที่ต้องการลดริ้วรอย หรือปรับรูปหน้าเรียว', '-', 2690, true),
  ('Botox', 'Botox เหมาขวด 100U (Nabota/Neuronox/Aestox)', 'โบท็อกซ์เหมาขวด 100 ยูนิต สำหรับลดกรามและริ้วรอยทั่วหน้า แกะกล่องเปิดขวดดูดยาต่อหน้า', 'ผู้ที่มีริ้วรอยเยอะ หรือต้องการฉีดหลายจุด', '-', 6900, true),
  ('Filler', 'Filler Neuramis (กล่องดำ)', 'ฟิลเลอร์สำหรับเติมเต็มร่องลึก หรือริมฝีปาก', 'ผู้ที่ต้องการเติมเต็มใบหน้า หรือปากกระจับ', '-', 2800, true),
  ('Filler', 'Filler E.P.T.Q. ทุกรุ่น', 'ฟิลเลอร์เกาหลีเกรดพรีเมียม 1cc', 'ผู้ที่ต้องการเติมเต็มใบหน้า ร่องแก้ม ปาก', '-', 4900, true),
  ('Filler', 'Filler Restylane ทุกรุ่น', 'ฟิลเลอร์สวีเดน 1cc', 'ผู้ที่ต้องการฟิลเลอร์พรีเมียม อยู่ได้นาน', '-', 11900, true),
  ('Surgery', 'เสริมจมูกใหม่ (Semi-Open)', 'เสริมจมูกใหม่เทคนิค Semi-Open ใช้ซิลิโคน Medical Grade (โปรโมชั่นเคสรีวิวจำกัดจำนวน)', 'ผู้ที่ต้องการเสริมจมูกใหม่', 'ฟรีเนื้อเยื่อรองปลายเฉพาะ 2 เคสแรก', 9999, true),
  ('Surgery', 'แก้จมูก (Semi-Open)', 'งานแก้จมูกเทคนิค Semi-Open', 'ผู้ที่เคยเสริมจมูกมาแล้วต้องการแก้ไข', '-', 14999, true),
  ('Weight Loss', 'ปากกาลดน้ำหนัก Mounjaro (รายครั้ง)', 'ปากกาลดน้ำหนักแบบปักรายครั้ง (2.5 mg)', 'ผู้ที่ต้องการลดน้ำหนักแบบปลอดภัย', 'ควบคุมโดยแพทย์', 1990, true),
  ('Weight Loss', 'ปากกาลดน้ำหนัก Mounjaro (เหมาแท่ง)', 'ปากกาลดน้ำหนักแบบเหมาด้าม นำกลับไปปักเองได้ 4 ครั้ง (2.5 mg)', 'ผู้ที่ต้องการลดน้ำหนักระยะยาว', 'ควบคุมโดยแพทย์', 12000, true),
  ('IV Drip', 'IV Drip ฉีดผิว (Aura White / Pink Pearl)', 'วิตามินบำรุงผิวผ่านสายน้ำเกลือ', 'ผู้ที่ต้องการให้ผิวกระจ่างใส ออร่า', 'มีโปร Happy Friday 499 บาท', 799, true);
INSERT INTO clinic_faqs (topic, question, answer, is_active)
VALUES
  ('Botox', 'โบท็อกซ์ราคาเท่าไหร่คะ', 'ตอนนี้ Botox จัดโปรพิเศษ เริ่มต้นที่ 50u ราคา 2,690.- ค่ะ และมีโปรเหมาขวด 100u เริ่มต้นที่ 5,900.- (MBtox) หรือ 6,900.- (Nabota, Aestox) แกะกล่องให้ดูต่อหน้าเลยค่ะ 😊', true),
  ('Filler', 'ฉีดฟิลเลอร์ปากราคาเท่าไหร่คะ', 'สำหรับฉีดปาก แอดมินแนะนำเป็น Neuramis กล่องดำ ราคาโปรโมชั่น 1cc เพียง 2,800.- (จาก 4,900) หรือ e.p.t.q. 1cc 4,900.- ค่ะ 😊', true),
  ('Surgery', 'เสริมจมูกเริ่มต้นเท่าไหร่คะ', 'ตอนนี้มีโปรโมชั่นเคสรีวิว เสริมจมูกใหม่เทคนิค Semi-Open ใช้ซิลิโคน Medical Grade เพียง 9,999.- (จาก 25,990.-) ปรึกษาและให้คุณหมอประเมินหน้าฟรี ไม่มีค่าใช้จ่ายค่ะ หากเป็นเคสแก้จะมีค่าแก้บวกเพิ่ม 5,000.- ค่ะ', true),
  ('Weight Loss', 'ปากกาลดน้ำหนักมีแบบไหนบ้าง', 'ทางคลินิกมีปากกาลดน้ำหนัก Mounjaro ให้บริการค่ะ มีทั้งแบบรายครั้ง (เริ่มต้น 1,990.- สำหรับ 2.5mg) และแบบเหมาแท่งนำกลับบ้านได้ ใช้ได้ 4 ครั้ง (12,000.- สำหรับ 2.5mg) ให้บริการภายใต้การดูแลของคุณหมอค่ะ', true),
  ('IV Drip', 'ฉีดผิวขาวกี่ครั้งเห็นผลคะ', 'การดริปวิตามินผิว แอดมินแนะนำให้ทำต่อเนื่อง 3 ครั้งขึ้นไปจะเริ่มเห็นการเปลี่ยนแปลงค่ะ ตอนนี้มีสูตร Healthy glow (599.-), Aura White (799.-) และ Pink Pearl (999.-) ค่ะ', true),
  ('Booking', 'ต้องมัดจำไหม จองคิวยังไง', 'หากคุณลูกค้าสนใจรับโปรโมชั่น แอดมินรบกวนมัดจำจองคิว 1,000 บาทนะคะ ส่วนที่เหลือสามารถชำระหน้าคลินิกวันที่เข้ามาทำหัตถการได้เลยค่ะ โปรโมชั่นมัดจำเก็บสิทธิ์ไว้ได้ถึง 3-6 เดือนค่ะ', true),
  ('General', 'คลินิกตั้งอยู่ที่ไหน', 'เอริกาคลินิกมีให้บริการเต็มรูปแบบค่ะ รบกวนคุณลูกค้าแจ้งชื่อ นามสกุล เบอร์โทรศัพท์ เพื่อทำประวัติและนัดหมายเวลาที่คุณหมอเข้าตรวจได้เลยค่ะ 🙏🏻', true);
